import org.owasp.encoder.Encode;

public class XSSFixedCode {
    public static void main(String[] args) {
        // Simulating user input
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Properly handling user input by encoding it before including it in the HTML response
        String safeUserInput = Encode.forHtml(userInput);

        // Constructing the safe HTML response
        String htmlResponse = "<html><body>Welcome, " + safeUserInput + "</body></html>";

        // Displaying the HTML response
        System.out.println(htmlResponse);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
